//   evaluated = Σ weight(enabled must_have + focus rules, outcome != unknown)
//   coverage  = mode='keyword' ? null : (total > 0 ? evaluated / total : 1.0)
//
// `deal_breaker` weight never enters `total`/`earned`/`evaluated` (D-04);
