  `scores?application_id=eq.${inp.application_id}&thesis_id=eq.${inp.thesis_id}&axis=eq.thesis_fit` +
  `&select=id,missing_flags&order=computed_at.desc`);
const match = existing.find(r => r.missing_flags && r.missing_flags._f07_input_fingerprint === inp.input_fingerprint);
let scoreId;
if (match) {
  scoreId = match.id;
} else {
  const row = await pg.call(this, 'POST', 'scores', {
    application_id: inp.application_id, founder_id: null, axis: 'thesis_fit',
    value: inp.fit, trend: null, confidence: inp.coverage,
    missing_flags: { missing_fields: inp.missing_fields || [], _f07_input_fingerprint: inp.input_fingerprint },
    input_claim_ids: claimIds,
    formula_version: "f07-rules-v1",
    prompt_version: inp.mode === 'full' ? "f07-extract-v1" : null,
    model: inp.mode === 'full' ? "gpt-5.6-luna" : null,
    thesis_id: inp.thesis_id,
  }, 'return=representation');
  scoreId = row[0].id;
}
return [{ json: { ...inp, score_id: scoreId } }];

